+fn make_multi_output_jaxpr(prim: Primitive, num_outputs: usize) -> Jaxpr {
+    let outvars: Vec<VarId> = (0..num_outputs).map(|i| VarId(2 + i as u32)).collect();
+    Jaxpr::new(
+        vec![VarId(1)],
+        vec![],
+        outvars.clone(),
+        vec![Equation {
+            primitive: prim,
+            inputs: smallvec![Atom::Var(VarId(1))],
+            outputs: outvars.into_iter().collect(),
+            params: BTreeMap::new(),
+            effects: vec![],
+            sub_jaxprs: vec![],
+        }],
+    )
+}
